def worker(steps: list[dict]) -> dict[str, str]:
    """
    Execute the plan. Steps with no #Ei dependencies run first (in parallel);
    later steps are run once their dependencies are resolved.
    Returns a mapping {"#E1": result, "#E2": result, ...}.
    """
    evidence: dict[str, str] = {}

    def resolve(arg: str) -> str:
        """Substitute #Ei placeholders with their resolved values."""
        for var, val in evidence.items():
            arg = arg.replace(var, val)
        return arg

    def is_ready(step: dict) -> bool:
        """True if all #Ei references in the argument are already resolved."""
        refs = re.findall(r"#E\d+", step["arg"])
        return all(r in evidence for r in refs)

    remaining = list(steps)
    while remaining:
        ready = [s for s in remaining if is_ready(s)]
        if not ready:
            raise RuntimeError(f"Circular dependency in plan: {remaining}")

        # Run ready steps in parallel
        with ThreadPoolExecutor() as executor:
            futures = {
                executor.submit(
                    TOOL_REGISTRY[s["tool"]], resolve(s["arg"])
                ): s["var"]
                for s in ready
            }
            for future in as_completed(futures):
                var = futures[future]
                evidence[var] = future.result()

        remaining = [s for s in remaining if s["var"] not in evidence]

    return evidence


SOLVER_PROMPT = """You are a solver. Given a question, a plan, and the evidence collected by
executing that plan, produce a concise final answer.
"""

def solver(task: str, steps: list[dict], evidence: dict[str, str]) -> str:
    """Call the Solver LLM with the task + plan + evidence."""
    plan_text = "\n".join(f"{s['var']} = {s['tool']}[{s['arg']}]" for s in steps)
    evidence_text = "\n".join(f"{k}: {v}" for k, v in evidence.items())
    user_msg = (
        f"Question: {task}\n\n"
        f"Plan:\n{plan_text}\n\n"
        f"Evidence collected:\n{evidence_text}"
    )
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        system=SOLVER_PROMPT,
        messages=[{"role": "user", "content": user_msg}],
    )
    return response.content[0].text


def rewoo(task: str) -> str:
    steps = planner(task)       # LLM call 1
    evidence = worker(steps)    # no LLM, tool calls only
    return solver(task, steps, evidence)  # LLM call 2


if __name__ == "__main__":
    result = rewoo("What is the GDP of France multiplied by the population of Japan?")
    print(result)

def worker_with_retry(steps: list[dict], max_retries: int = 2) -> dict[str, str]:
    """
    Worker that retries failed tool calls up to max_retries times.
    Passes error strings to downstream steps so the Solver sees them.
    """
    evidence: dict[str, str] = {}

    def resolve(arg: str) -> str:
        for var, val in evidence.items():
            arg = arg.replace(var, val)
        return arg

    def is_ready(step: dict) -> bool:
        return all(r in evidence for r in re.findall(r"#E\d+", step["arg"]))

    remaining = list(steps)
    while remaining:
        ready = [s for s in remaining if is_ready(s)]
        if not ready:
            break  # Circular dependency or unresolvable — stop gracefully

        for step in ready:
            tool_fn = TOOL_REGISTRY.get(step["tool"])
            if tool_fn is None:
                evidence[step["var"]] = f"[Error: unknown tool '{step['tool']}']"
            else:
                arg = resolve(step["arg"])
                last_error = None
                for attempt in range(max_retries + 1):
                    try:
                        evidence[step["var"]] = tool_fn(arg)
                        break
                    except Exception as exc:
                        last_error = exc
                else:
                    evidence[step["var"]] = f"[Error after {max_retries} retries: {last_error}]"

        remaining = [s for s in remaining if s["var"] not in evidence]

    return evidence
